        case .staging:
            return "https://staging.example.com"
        case .production:
            return "https://prod.example.com"
        }
    }
}

class NetworkService {
    
    static let shared = NetworkService()
    private init() {}
    
    private var environment: Environment = .development
    
    func setEnvironment(_ environment: Environment) {
        self.environment = environment
    }
    
    private let urlSession = URLSession.shared
    
    func request(method: HTTPMethod, path: String, parameters: [String: Any]? = nil, completion: @escaping (Data?, URLResponse?, Error?) -> Void) {
        
        var urlComponents = URLComponents(string: environment.baseURL + path)
        
        if let parameters = parameters, method == .get {
            urlComponents?.queryItems = parameters.map { URLQueryItem(name: $0.key, value: "\($0.value)")}
        }
        
        guard let url = urlComponents?.url else {
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method.rawValue
        
        if let parameters = parameters, method == .post {
            request.httpBody = try? JSONSerialization.data(withJSONObject: parameters, options: .prettyPrinted)
        }
        
        let task = urlSession.dataTask(with: request) { data, response, error in
            DispatchQueue.main.async {
                completion(data, response, error)
            }
        }
        task.resume()
    }
}